import React, { useState, useEffect } from "react";
import bookingService from "../services/bookingService";
import { useAuth } from "../context/AuthContext";
import { useToast } from "../components/Toast";

export default function Bookings() {
  const { user } = useAuth();
  const showToast = useToast();

  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);

  // ✅ modal state
  const [selectedBooking, setSelectedBooking] = useState(null);
  const [selectedSeats, setSelectedSeats] = useState([]);

  const load = () => {
    if (!user) return;

    bookingService
      .getByUser(user.id)
      .then(setBookings)
      .catch(() => showToast("Error loading bookings", "error"))
      .finally(() => setLoading(false));
  };

  useEffect(() => {
    load();
  }, [user]);

  // ✅ FULL CANCEL
  const cancelBooking = async (id) => {
    if (!window.confirm("Cancel full booking?")) return;

    await bookingService.cancel(id);
    showToast("Booking cancelled", "success");
    load();
  };

  // ✅ OPEN MODAL
  const openCancelModal = (booking) => {
    setSelectedBooking(booking);
    setSelectedSeats([]);
  };

  // ✅ TOGGLE SEAT
  const toggleSeat = (seatId) => {
    setSelectedSeats((prev) =>
      prev.includes(seatId)
        ? prev.filter((id) => id !== seatId)
        : [...prev, seatId]
    );
  };

  // ✅ CONFIRM PARTIAL CANCEL
  const confirmCancel = async () => {
    if (selectedSeats.length === 0) {
      showToast("Select at least one seat", "error");
      return;
    }

    try {
      await bookingService.partialCancel(
        selectedBooking.bookingId,
        selectedSeats
      );

      showToast("Seats cancelled", "success");
      setSelectedBooking(null);
      load();
    } catch {
      showToast("Cancel failed", "error");
    }
  };

  return (
    <div className="container">
      <h2>My Bookings</h2>

      {loading ? (
        <p>Loading...</p>
      ) : bookings.length === 0 ? (
        <p>No bookings</p>
      ) : (
        bookings.map((b) => (
          <div key={b.bookingId} className="card" style={{ margin: "1rem 0" }}>
            <h3>🎬 {b.movieTitle}</h3>

            <p>
              🏛️ {b.theaterName} — {b.screenName}
            </p>

            <p>
              💺 Seats: {b.seats?.map((s) => s.seatNumber).join(", ")}
            </p>

            <p>💰 ₹{b.totalPrice}</p>
            <p>Status: {b.bookingStatus}</p>

            {b.bookingStatus === "CONFIRMED" && (
              <>
                <button onClick={() => cancelBooking(b.bookingId)}>
                  Cancel Full
                </button>

                <button
                  style={{ marginLeft: "10px" }}
                  onClick={() => openCancelModal(b)}
                >
                  Cancel Seats
                </button>
              </>
            )}
          </div>
        ))
      )}

      {/* 🔥 MODAL UI */}
      {selectedBooking && (
        <div className="modal-overlay">
          <div className="modal">
            <h3>Select Seats to Cancel</h3>

            {selectedBooking.seats.map((seat) => (
              <label key={seat.id} style={{ display: "block" }}>
                <input
                  type="checkbox"
                  onChange={() => toggleSeat(seat.id)}
                />
                {seat.seatNumber}
              </label>
            ))}

            <br />

            <button onClick={confirmCancel}>
              Confirm Cancel
            </button>

            <button onClick={() => setSelectedBooking(null)}>
              Close
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
